import{_ as s,V as a,W as e,$ as t,X as n,Y as i,Z as l}from"./framework-f1cb4d02.js";const o={},p=n("h2",{id:"简介",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#简介","aria-hidden":"true"},"#"),i(" 简介")],-1),c=n("p",null,"单例模式是一种常用的模式, 有一些对象往往只需要一个, 比如线程池、全局缓存、浏览器中的 window 对象等. 单例模式用于保证一个类仅有一个实例, 并提供一个访问它的全局访问点",-1),u=l(`<h2 id="优缺点" tabindex="-1"><a class="header-anchor" href="#优缺点" aria-hidden="true">#</a> 优缺点</h2><ul><li>优点 <ol><li>由于单例模式在内存中只有一个实例, 减少了内存开支, 特别是一个对象需要频繁地创建、销毁时, 而且创建或销毁时性能又无法优化, 单例模式的优势就非常明显</li><li>由于单例模式只生成一个实例, 所以减少了系统的性能开销, 当一个对象的产生需要比较多的资源时, 如读取配置、产生其他依赖对象时, 则可以通过在应用启动时直接产生一个单例对象, 然后用永久驻留内存的方式解决</li><li>单例模式可以在系统设置全局的访问点, 优化和共享资源的访问</li><li>避免对资源的多重占用, 避免对同一个资源文件的同时操作, 造成文件状体不一致</li></ol></li><li>缺点 <ol><li>单例模式一般没有接口，扩展很困难，若要扩展，除了修改代码基本上没有第二种途径可以实现</li></ol></li></ul><h2 id="应用场景" tabindex="-1"><a class="header-anchor" href="#应用场景" aria-hidden="true">#</a> 应用场景</h2><ul><li>系统只需要一个实例对象，如系统要求提供一个唯一的序列号生成器或资源管理器，或者需要考虑资源消耗太大而只允许创建一个对象</li><li>创建对象时耗时过多或耗资源过多，但又经常用到的对象</li><li>需要频繁实例化然后销毁的对象</li></ul><h2 id="特点" tabindex="-1"><a class="header-anchor" href="#特点" aria-hidden="true">#</a> 特点</h2><ol><li>单例类只有一个实例对象</li><li>该单例对象必须由单例类自行创建</li><li>单例类对外提供一个访问该单例的全局访问点</li></ol><h3 id="懒汉式单例" tabindex="-1"><a class="header-anchor" href="#懒汉式单例" aria-hidden="true">#</a> 懒汉式单例</h3><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token keyword">class</span> <span class="token class-name">LazySingleton</span> <span class="token punctuation">{</span>
  <span class="token keyword">private</span> <span class="token keyword">static</span> singleton<span class="token operator">:</span> LazySingleton<span class="token punctuation">;</span>

  <span class="token keyword">private</span> <span class="token function">constructor</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>

  <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token function">getInstance</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">:</span> LazySingleton <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>LazySingleton<span class="token punctuation">.</span>singleton<span class="token punctuation">)</span> <span class="token punctuation">{</span>
      LazySingleton<span class="token punctuation">.</span>singleton <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">LazySingleton</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span> LazySingleton<span class="token punctuation">.</span>singleton<span class="token punctuation">;</span>
  <span class="token punctuation">}</span>

  <span class="token comment">// 别的方法</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="饿汉式单例" tabindex="-1"><a class="header-anchor" href="#饿汉式单例" aria-hidden="true">#</a> 饿汉式单例</h3><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token keyword">class</span> <span class="token class-name">HungrySingleton</span> <span class="token punctuation">{</span>
  <span class="token keyword">private</span> <span class="token keyword">static</span> singleton<span class="token operator">:</span> HungrySingleton <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">HungrySingleton</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token keyword">private</span> <span class="token function">constructor</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>

  <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token function">getInstance</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">:</span> HungrySingleton <span class="token punctuation">{</span>
    <span class="token keyword">return</span> LazySingleton<span class="token punctuation">.</span>singleton<span class="token punctuation">;</span>
  <span class="token punctuation">}</span>

  <span class="token comment">// 别的方法</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,10);function r(d,k){return a(),e("div",null,[p,c,t(" more "),u])}const m=s(o,[["render",r],["__file","singleton-pattern.html.vue"]]);export{m as default};
